# quality/retrieval_metrics.py
# Layer 3: precision, MRR, nDCG computed against a labelled evaluation set

from __future__ import annotations
import math
from dataclasses import dataclass


@dataclass
class RetrievalMetrics:
    precision_at_k: float
    mrr: float
    ndcg_at_k: float
    k: int


def precision_at_k(retrieved: list[str], relevant: set[str], k: int) -> float:
    top_k = retrieved[:k]
    hits = sum(1 for doc_id in top_k if doc_id in relevant)
    return hits / k


def mean_reciprocal_rank(retrieved: list[str], relevant: set[str]) -> float:
    for rank, doc_id in enumerate(retrieved, start=1):
        if doc_id in relevant:
            return 1.0 / rank
    return 0.0


def ndcg_at_k(retrieved: list[str], relevant: set[str], k: int) -> float:
    """Binary relevance nDCG."""
    def dcg(docs: list[str]) -> float:
        return sum(
            (1 / math.log2(i + 2))
            for i, doc_id in enumerate(docs[:k])
            if doc_id in relevant
        )
    ideal = dcg(list(relevant)[:k])  # ideal order: all relevant first
    actual = dcg(retrieved)
    return actual / ideal if ideal > 0 else 0.0


def evaluate_retrieval(
    eval_set: list[dict],  # [{"query": ..., "relevant_doc_ids": [...], "retrieved": [...]}]
    k: int = 5,
) -> RetrievalMetrics:
    p_scores, mrr_scores, ndcg_scores = [], [], []
    for item in eval_set:
        relevant = set(item["relevant_doc_ids"])
        retrieved = item["retrieved"]
        p_scores.append(precision_at_k(retrieved, relevant, k))
        mrr_scores.append(mean_reciprocal_rank(retrieved, relevant))
        ndcg_scores.append(ndcg_at_k(retrieved, relevant, k))
    return RetrievalMetrics(
        precision_at_k=sum(p_scores) / len(p_scores),
        mrr=sum(mrr_scores) / len(mrr_scores),
        ndcg_at_k=sum(ndcg_scores) / len(ndcg_scores),
        k=k,
    )
